@app.route("/annotations", methods=["POST"])
def submit_annotation():
    data = request.get_json(force=True, silent=True) or {}
    image_id = data.get("image_id")
    annotator_id = data.get("annotator_id")
    label = data.get("label")

    if image_id is None or not annotator_id or label is None:
        return jsonify({"error": "image_id, annotator_id, and label are required"}), 400
    if not image_exists(int(image_id)):
        return jsonify({"error": "image not found"}), 404

    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("""
            INSERT INTO annotations (image_id, annotator_id, label, created_at)
            VALUES (?, ?, ?, ?)
            ON CONFLICT(image_id, annotator_id) DO UPDATE SET
                label=excluded.label,
                created_at=excluded.created_at
        """, (int(image_id), str(annotator_id), str(label), time.time()))
        conn.commit()
        conn.close()
        recompute_aggregate(int(image_id))

    conn = get_conn()
    cur = conn.cursor()
    cur.execute("SELECT * FROM aggregated_labels WHERE image_id = ?", (int(image_id),))
    agg = cur.fetchone()
    conn.close()
    return jsonify({
        "status": "ok",
        "image_id": int(image_id),
        "annotator_id": str(annotator_id),
        "label": str(label),
        "aggregated_label": dict(agg) if agg else None
    }), 201


