@app.route("/aggregate/recompute", methods=["POST"])
def recompute_all():
    conn = get_conn()
    cur = conn.cursor()
    cur.execute("SELECT id FROM images")
    image_ids = [r["id"] for r in cur.fetchall()]
    conn.close()
    with db_lock:
        for image_id in image_ids:
            recompute_aggregate(image_id)
    return jsonify({"status": "ok", "recomputed": len(image_ids)})


@app.route("/train", methods=["POST"])
def train():
    if tf is None:
        return jsonify({"error": "tensorflow is not installed"}), 500

    data = request.get_json(force=True, silent=True) or {}
    image_size = int(data.get("image_size", 64))
    epochs = int(data.get("epochs", 3))
    batch_size = int(data.get("batch_size", 8))

    conn = get_conn()
    cur = conn.cursor()
    cur.execute("""
        SELECT i.path, a.label
        FROM images i
        JOIN aggregated_labels a ON i.id = a.image_id
        ORDER BY i.id ASC
    """)
    rows = cur.fetchall()
    conn.close()

    if not rows:
        return jsonify({"error": "no aggregated labeled data available"}), 400

    labels = sorted(list({r["label"] for r in rows}))
    label_to_idx = {label: idx for idx, label in enumerate(labels)}

    X = []
    y = []
    for r in rows:
        try:
            X.append(load_image_for_model(r["path"], image_size))
            y.append(label_to_idx[r["label"]])
        except Exception:
            continue

    if not X:
        return jsonify({"error": "failed to load training images"}), 400

    X = np.stack(X, axis=0)
    y = np.asarray(y, dtype=np.int32)

    model = build_model(num_classes=len(labels), image_size=image_size)
    history = model.fit(X, y, epochs=epochs, batch_size=batch_size, verbose=1)

    ts = int(time.time())
    model_path = os.path.join(MODEL_DIR, f"model_{ts}.keras")
    model.save(model_path)

    conn = get_conn()
    cur = conn.cursor()
    cur.execute("""
        INSERT INTO training_runs (model_path, labels_json, image_size, epochs, batch_size, created_at)
        VALUES (?, ?, ?, ?, ?, ?)
    """, (model_path, json.dumps(label_to_idx), image_size, epochs, batch_size, time.time()))
    run_id = cur.lastrowid
    conn.commit()
    conn.close()

    return jsonify({
        "status": "trained",
        "training_run_id": run_id,
        "model_path": model_path,
        "num_samples": int(len(X)),
        "num_classes": int(len(labels)),
        "labels": label_to_idx,
        "final_loss": float(history.history["loss"][-1]) if "loss" in history.history else None,
        "final_accuracy": float(history.history["accuracy"][-1]) if "accuracy" in history.history else None
    })


