@app.route("/predict", methods=["POST"])
def predict():
    if tf is None:
        return jsonify({"error": "tensorflow is not installed"}), 500

    model_path = request.form.get("model_path")
    labels_json = request.form.get("labels_json")

    if not model_path or not os.path.exists(model_path):
        return jsonify({"error": "valid model_path is required"}), 400
    if "file" not in request.files:
        return jsonify({"error": "missing file"}), 400

    try:
        label_to_idx = json.loads(labels_json) if labels_json else None
        if label_to_idx is None:
            conn = get_conn()
            cur = conn.cursor()
            cur.execute("""
                SELECT labels_json
                FROM training_runs
                WHERE model_path = ?
                ORDER BY id DESC
                LIMIT 1
            """, (model_path,))
            row = cur.fetchone()
            conn.close()
            if not row:
                return jsonify({"error": "labels_json not provided and no training metadata found"}), 400
            label_to_idx = json.loads(row["labels_json"])
    except Exception:
        return jsonify({"error": "invalid labels_json"}), 400

    idx_to_label = {int(v): k for k, v in label_to_idx.items()}
    file = request.files["file"]
    image_size = int(request.form.get("image_size", 64))

    try:
        img = Image.open(io.BytesIO(file.read())).convert("RGB").resize((image_size, image_size))
        arr = np.asarray(img, dtype=np.float32) / 255.0
        arr = np.expand_dims(arr, axis=0)
        model = tf.keras.models.load_model(model_path)
        probs = model.predict(arr, verbose=0)[0]
        pred_idx = int(np.argmax(probs))
        pred_label = idx_to_label.get(pred_idx, str(pred_idx))
        return jsonify({
            "predicted_index": pred_idx,
            "predicted_label": pred_label,
            "probabilities": probs.tolist()
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500


